mapper.select:
WITH HOURS AS ( SELECT LPAD(LEVEL - 1, 2, '0') AS HOUR FROM DUAL CONNECT BY LEVEL <= 24 ), STATUS_STATS AS ( SELECT TO_CHAR(c.CART_STATUSDATE, 'HH24') AS HOUR, COUNT(*) AS STATUS_COUNT FROM CART c JOIN FURNITURE f ON c.F_CODE = f.F_CODE
c.F_STATUS = 'Y' AND c.CART_STATUSDATE IS NOT NULL
AND c.F_DSTATUS = #{f_dstatus}
AND c.F_DSTATUS = #{F_DSTATUS}
AND c.F_DSTATUS = 5
GROUP BY TO_CHAR(c.CART_STATUSDATE, 'HH24') ) SELECT h.HOUR AS "hour", NVL(s.STATUS_COUNT, 0) AS "statusCount" FROM HOURS h LEFT JOIN STATUS_STATS s ON h.HOUR = s.HOUR ORDER BY h.HOUR

WITH PAY_TO_CONFIRM AS ( SELECT COUNT(*) AS TARGET_COUNT, ROUND(AVG(c.CART_STATUSDATE - c.CART_PAYDATE), 2) AS AVG_DAYS, ROUND(AVG((c.CART_STATUSDATE - c.CART_PAYDATE) * 24), 2) AS AVG_HOURS, ROUND(AVG((c.CART_STATUSDATE - c.CART_PAYDATE) * 24 * 60), 2) AS AVG_MINUTES FROM CART c JOIN FURNITURE f ON c.F_CODE = f.F_CODE
c.F_STATUS = 'Y' AND c.F_DSTATUS = 5 AND c.CART_PAYDATE IS NOT NULL AND c.CART_STATUSDATE IS NOT NULL AND c.CART_STATUSDATE >= c.CART_PAYDATE
), CART_TO_PAY AS ( SELECT COUNT(*) AS TARGET_COUNT, ROUND(AVG(c.CART_PAYDATE - c.CART_CREATEDDATE), 2) AS AVG_DAYS, ROUND(AVG((c.CART_PAYDATE - c.CART_CREATEDDATE) * 24), 2) AS AVG_HOURS, ROUND(AVG((c.CART_PAYDATE - c.CART_CREATEDDATE) * 24 * 60), 2) AS AVG_MINUTES FROM CART c JOIN FURNITURE f ON c.F_CODE = f.F_CODE
c.F_STATUS = 'Y' AND c.CART_CREATEDDATE IS NOT NULL AND c.CART_PAYDATE IS NOT NULL AND c.CART_PAYDATE >= c.CART_CREATEDDATE
) SELECT NVL(ptc.TARGET_COUNT, 0) AS "payToConfirmTargetCount", NVL(ptc.AVG_DAYS, 0) AS "avgPayToConfirmDays", NVL(ptc.AVG_HOURS, 0) AS "avgPayToConfirmHours", NVL(ptc.AVG_MINUTES, 0) AS "avgPayToConfirmMinutes", NVL(ctp.TARGET_COUNT, 0) AS "cartToPayTargetCount", NVL(ctp.AVG_DAYS, 0) AS "avgCartToPayDays", NVL(ctp.AVG_HOURS, 0) AS "avgCartToPayHours", NVL(ctp.AVG_MINUTES, 0) AS "avgCartToPayMinutes" FROM PAY_TO_CONFIRM ptc CROSS JOIN CART_TO_PAY ctp

WITH PAID_CART AS ( SELECT c.C_CODE, c.F_CODE, c.PAY_TOTAL, c.USE_POINT, c.SAVE_POINT, c.COUPON_DISCOUNT, NVL(c.PAY_TOTAL, 0) + NVL(c.USE_POINT, 0) + NVL(c.COUPON_DISCOUNT, 0) AS BEFORE_DISCOUNT_AMOUNT FROM CART c JOIN FURNITURE f ON c.F_CODE = f.F_CODE
c.F_STATUS = 'Y' AND NVL(c.F_DSTATUS, 0) != -1
) SELECT COUNT(*) AS "totalPayCount", COUNT(CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 THEN 1 END) AS "couponUseCount", COUNT(CASE WHEN NVL(COUPON_DISCOUNT, 0) = 0 THEN 1 END) AS "couponNotUseCount", CASE WHEN COUNT(*) = 0 THEN 0 ELSE ROUND(COUNT(CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 THEN 1 END) / COUNT(*) * 100, 2) END AS "couponUseRate", NVL(SUM(NVL(COUPON_DISCOUNT, 0)), 0) AS "totalCouponDiscount", NVL(ROUND(AVG(NVL(COUPON_DISCOUNT, 0)), 0), 0) AS "avgCouponDiscountAll", NVL(ROUND(AVG(CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 THEN COUPON_DISCOUNT END), 0), 0) AS "avgCouponDiscountUsed", NVL(MAX(NVL(COUPON_DISCOUNT, 0)), 0) AS "maxCouponDiscount", NVL(SUM(BEFORE_DISCOUNT_AMOUNT), 0) AS "totalBeforeDiscountAmount", CASE WHEN NVL(SUM(BEFORE_DISCOUNT_AMOUNT), 0) = 0 THEN 0 ELSE ROUND(SUM(NVL(COUPON_DISCOUNT, 0)) / SUM(BEFORE_DISCOUNT_AMOUNT) * 100, 2) END AS "couponDiscountRate", COUNT(CASE WHEN NVL(USE_POINT, 0) > 0 THEN 1 END) AS "pointUseCount", COUNT(CASE WHEN NVL(USE_POINT, 0) = 0 THEN 1 END) AS "pointNotUseCount", CASE WHEN COUNT(*) = 0 THEN 0 ELSE ROUND(COUNT(CASE WHEN NVL(USE_POINT, 0) > 0 THEN 1 END) / COUNT(*) * 100, 2) END AS "pointUseRate", NVL(SUM(NVL(USE_POINT, 0)), 0) AS "totalUsePoint", NVL(ROUND(AVG(NVL(USE_POINT, 0)), 0), 0) AS "avgUsePointAll", NVL(ROUND(AVG(CASE WHEN NVL(USE_POINT, 0) > 0 THEN USE_POINT END), 0), 0) AS "avgUsePointUsed", NVL(MAX(NVL(USE_POINT, 0)), 0) AS "maxUsePoint", NVL(SUM(NVL(SAVE_POINT, 0)), 0) AS "totalSavePoint", NVL(ROUND(AVG(NVL(SAVE_POINT, 0)), 0), 0) AS "avgSavePoint", CASE WHEN NVL(SUM(NVL(PAY_TOTAL, 0)), 0) = 0 THEN 0 ELSE ROUND(SUM(NVL(SAVE_POINT, 0)) / SUM(NVL(PAY_TOTAL, 0)) * 100, 2) END AS "savePointRate" FROM PAID_CART

WITH PAID_CART AS ( SELECT c.C_CODE, c.PAY_TOTAL, c.USE_POINT, c.COUPON_DISCOUNT FROM CART c JOIN FURNITURE f ON c.F_CODE = f.F_CODE
c.F_STATUS = 'Y' AND NVL(c.F_DSTATUS, 0) != -1
), USE_TYPE_BASE AS ( SELECT CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) > 0 THEN 'couponPoint' WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) = 0 THEN 'couponOnly' WHEN NVL(COUPON_DISCOUNT, 0) = 0 AND NVL(USE_POINT, 0) > 0 THEN 'pointOnly' ELSE 'none' END AS USE_TYPE, CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) > 0 THEN 1 WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) = 0 THEN 2 WHEN NVL(COUPON_DISCOUNT, 0) = 0 AND NVL(USE_POINT, 0) > 0 THEN 3 ELSE 4 END AS SORT_NO, PAY_TOTAL, USE_POINT, COUPON_DISCOUNT FROM PAID_CART ) SELECT USE_TYPE AS "useType", COUNT(*) AS "orderCount", CASE WHEN SUM(COUNT(*)) OVER () = 0 THEN 0 ELSE ROUND(COUNT(*) / SUM(COUNT(*)) OVER () * 100, 2) END AS "orderRate", NVL(SUM(NVL(PAY_TOTAL, 0)), 0) AS "totalPayAmount", NVL(SUM(NVL(COUPON_DISCOUNT, 0)), 0) AS "totalCouponDiscount", NVL(SUM(NVL(USE_POINT, 0)), 0) AS "totalUsePoint", NVL(ROUND(AVG(NVL(PAY_TOTAL, 0)), 0), 0) AS "avgPayAmount" FROM USE_TYPE_BASE GROUP BY USE_TYPE, SORT_NO ORDER BY SORT_NO

WITH PAID_CART AS ( SELECT c.C_CODE, c.PAY_TOTAL, c.USE_POINT, c.COUPON_DISCOUNT, NVL(c.PAY_TOTAL, 0) + NVL(c.USE_POINT, 0) + NVL(c.COUPON_DISCOUNT, 0) AS BEFORE_DISCOUNT_AMOUNT FROM CART c JOIN FURNITURE f ON c.F_CODE = f.F_CODE
c.F_STATUS = 'Y' AND NVL(c.F_DSTATUS, 0) != -1
), COMPARE_BASE AS ( SELECT CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) > 0 THEN 'couponPoint' WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) = 0 THEN 'couponOnly' WHEN NVL(COUPON_DISCOUNT, 0) = 0 AND NVL(USE_POINT, 0) > 0 THEN 'pointOnly' ELSE 'none' END AS USE_TYPE, CASE WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) > 0 THEN 1 WHEN NVL(COUPON_DISCOUNT, 0) > 0 AND NVL(USE_POINT, 0) = 0 THEN 2 WHEN NVL(COUPON_DISCOUNT, 0) = 0 AND NVL(USE_POINT, 0) > 0 THEN 3 ELSE 4 END AS SORT_NO, PAY_TOTAL, USE_POINT, COUPON_DISCOUNT, BEFORE_DISCOUNT_AMOUNT FROM PAID_CART ) SELECT USE_TYPE AS "useType", COUNT(*) AS "orderCount", NVL(SUM(NVL(PAY_TOTAL, 0)), 0) AS "totalPayAmount", NVL(ROUND(AVG(NVL(PAY_TOTAL, 0)), 0), 0) AS "avgPayAmount", NVL(SUM(NVL(BEFORE_DISCOUNT_AMOUNT, 0)), 0) AS "totalBeforeDiscountAmount", NVL(ROUND(AVG(NVL(BEFORE_DISCOUNT_AMOUNT, 0)), 0), 0) AS "avgBeforeDiscountAmount", NVL(SUM(NVL(COUPON_DISCOUNT, 0)), 0) AS "totalCouponDiscount", NVL(ROUND(AVG(NVL(COUPON_DISCOUNT, 0)), 0), 0) AS "avgCouponDiscount", NVL(SUM(NVL(USE_POINT, 0)), 0) AS "totalUsePoint", NVL(ROUND(AVG(NVL(USE_POINT, 0)), 0), 0) AS "avgUsePoint", CASE WHEN NVL(SUM(NVL(BEFORE_DISCOUNT_AMOUNT, 0)), 0) = 0 THEN 0 ELSE ROUND((SUM(NVL(COUPON_DISCOUNT, 0)) + SUM(NVL(USE_POINT, 0))) / SUM(NVL(BEFORE_DISCOUNT_AMOUNT, 0)) * 100, 2) END AS "discountAndPointRate" FROM COMPARE_BASE GROUP BY USE_TYPE, SORT_NO ORDER BY SORT_NO
